//! Conformance tests — `ferrotorch_ml::metrics` module.
//!
//! Tracking issue: <https://github.com/dollspace-gay/ferrotorch/issues/840>.
//!
//! Reference library: scikit-learn 1.5.2 (pinned).
//! Fixtures generated by `scripts/regenerate_ml_fixtures.py`.
//!
//! Organisation:
//! - Regression metrics (r2, mse, rmse, mae, mape, medae, max_error, evs)
//! - Classification metrics (accuracy, precision, recall, f1, roc_auc,
//!   log_loss, confusion_matrix, hamming, balanced_acc, mcc, kappa,
//!   brier, d2_brier, top_k, zero_one, avg_precision)
//! - Ranking metrics (dcg, ndcg, coverage_error, lrap, label_ranking_loss)
//! - Clustering metrics (ari, ami, nmi, homogeneity, completeness,
//!   v_measure, fowlkes_mallows, silhouette, davies_bouldin,
//!   calinski_harabasz)
//!
//! Divergences → `cascade_skip!()` with the filed tracking issue.

use std::path::PathBuf;

use ferrotorch_core::{Tensor, TensorStorage};
use ferrotorch_ml::metrics::{
    Average, accuracy_score, adjusted_mutual_info_score, adjusted_rand_score,
    average_precision_score, balanced_accuracy_score, brier_score_loss, calinski_harabasz_score,
    cohen_kappa_score, completeness_score, confusion_matrix, coverage_error, d2_brier_score,
    davies_bouldin_score, dcg_score, explained_variance_score, f1_score, fowlkes_mallows_score,
    hamming_loss, homogeneity_score, label_ranking_average_precision_score, label_ranking_loss,
    log_loss, matthews_corrcoef, max_error, mean_absolute_error, mean_absolute_percentage_error,
    mean_squared_error, median_absolute_error, ndcg_score, normalized_mutual_info_score,
    precision_score, r2_score, recall_score, roc_auc_score, root_mean_squared_error,
    silhouette_score, top_k_accuracy_score, v_measure_score, zero_one_loss,
};
use serde::Deserialize;

// ---------------------------------------------------------------------------
// Fixture loading
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize, Clone)]
struct FixtureFile {
    #[allow(dead_code, reason = "metadata kept for diagnostics")]
    metadata: serde_json::Value,
    fixtures: Vec<Fixture>,
}

// All array-typed fields use `serde_json::Value` to handle both 1-D
// (`[1.0, 2.0, ...]`) and 2-D (`[[...], [...]]`) JSON arrays that appear
// across regression / classification / ranking / clustering fixtures.
// Concrete extractions are done by the `as_f64_vec` / `as_2d_*` helpers below.
#[derive(Debug, Deserialize, Clone)]
struct Fixture {
    op: String,
    // Array fields stored as Value to tolerate 1-D and 2-D shapes.
    #[serde(default)]
    y_true: Option<serde_json::Value>,
    #[serde(default)]
    y_pred: Option<serde_json::Value>,
    #[serde(default)]
    y_score: Option<serde_json::Value>,
    #[serde(default)]
    y_prob: Option<serde_json::Value>,
    #[serde(default)]
    labels_true: Option<serde_json::Value>,
    #[serde(default)]
    labels_pred: Option<serde_json::Value>,
    #[serde(default)]
    x: Option<serde_json::Value>,
    #[serde(default)]
    labels: Option<serde_json::Value>,
    // `expected` is f64 for most ops but a nested array for confusion_matrix.
    // Store as Value and extract lazily via `expected_f64` / `expected_cm` helpers.
    #[serde(default)]
    expected: Option<serde_json::Value>,
    #[serde(default)]
    tol: Option<f64>,
    #[serde(flatten)]
    _rest: serde_json::Value,
}

/// Extract `expected` as f64. Panics if absent or not a JSON number.
fn expected_f64(f: &Fixture) -> f64 {
    f.expected
        .as_ref()
        .expect("expected field missing")
        .as_f64()
        .expect("expected field is not a number")
}

/// Extract `expected` as `Vec<Vec<usize>>` (for confusion_matrix).
fn expected_cm(f: &Fixture) -> Vec<Vec<usize>> {
    serde_json::from_value(f.expected.as_ref().expect("expected field missing").clone())
        .expect("expected field is not a Vec<Vec<usize>>")
}

/// Extract a flat `Vec<f64>` from a 1-D JSON array field.
fn as_f64_vec(v: &serde_json::Value, label: &str) -> Vec<f64> {
    v.as_array()
        .unwrap_or_else(|| panic!("{label}: expected JSON array"))
        .iter()
        .map(|x| {
            x.as_f64()
                .unwrap_or_else(|| panic!("{label}: expected f64 element, got {x}"))
        })
        .collect()
}

fn load_fixtures() -> FixtureFile {
    let p = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures.json");
    let bytes = std::fs::read(&p).unwrap_or_else(|e| {
        panic!(
            "read {} failed: {e}. Run python3 scripts/regenerate_ml_fixtures.py first.",
            p.display()
        )
    });
    serde_json::from_slice(&bytes).unwrap_or_else(|e| panic!("parse {}: {e}", p.display()))
}

fn find(file: &FixtureFile, op: &str) -> Fixture {
    file.fixtures
        .iter()
        .find(|f| f.op == op)
        .unwrap_or_else(|| panic!("no fixture with op={op:?}"))
        .clone()
}

// ---------------------------------------------------------------------------
// Helper: build a 1-D Tensor<f64> from a slice
// ---------------------------------------------------------------------------

fn tensor1d(data: &[f64]) -> Tensor<f64> {
    Tensor::from_storage(TensorStorage::cpu(data.to_vec()), vec![data.len()], false)
        .expect("build 1-D tensor")
}

fn tensor2d(data: Vec<f64>, rows: usize, cols: usize) -> Tensor<f64> {
    Tensor::from_storage(TensorStorage::cpu(data), vec![rows, cols], false)
        .expect("build 2-D tensor")
}

// ---------------------------------------------------------------------------
// Tolerance helpers
// ---------------------------------------------------------------------------

fn check_f64(actual: f64, expected: f64, tol: f64, label: &str) {
    let diff = (actual - expected).abs();
    assert!(
        diff <= tol,
        "{label}: actual={actual:.8e}, expected={expected:.8e}, diff={diff:.3e} > tol={tol:.3e}"
    );
}

// ---------------------------------------------------------------------------
// Helper: parse 1-D or 2-D JSON value into a flat Vec<f64>
// ---------------------------------------------------------------------------

fn parse_score_1d(v: &serde_json::Value) -> Vec<f64> {
    v.as_array()
        .expect("score array")
        .iter()
        .map(|x| x.as_f64().expect("f64"))
        .collect()
}

fn parse_score_2d(v: &serde_json::Value) -> (Vec<f64>, usize, usize) {
    let rows_v = v.as_array().expect("outer array");
    let rows = rows_v.len();
    let mut flat = Vec::new();
    let mut cols = 0;
    for row in rows_v {
        let row_v = row.as_array().expect("inner array");
        cols = row_v.len();
        for x in row_v {
            flat.push(x.as_f64().expect("f64"));
        }
    }
    (flat, rows, cols)
}

// ============================================================================
// REGRESSION METRICS
// ============================================================================

#[test]
fn r2_score_matches_sklearn() {
    let file = load_fixtures();
    let f = find(&file, "r2_score");
    let yt = tensor1d(&as_f64_vec(f.y_true.as_ref().expect("y_true"), "r2/y_true"));
    let yp = tensor1d(&as_f64_vec(f.y_pred.as_ref().expect("y_pred"), "r2/y_pred"));
    let actual = r2_score(&yt, &yp).expect("r2_score");
    check_f64(actual, expected_f64(&f), f.tol.unwrap_or(1e-9), "r2_score");
}

#[test]
fn r2_score_perfect_is_one() {
    let file = load_fixtures();
    let f = find(&file, "r2_score_perfect");
    let y = tensor1d(&as_f64_vec(
        f.y_true.as_ref().expect("y_true"),
        "r2_perfect/y_true",
    ));
    let actual = r2_score(&y, &y).expect("r2_score_perfect");
    check_f64(actual, 1.0, 1e-12, "r2_score_perfect");
}

