#[test]
fn fixture_file_covers_every_metrics_op() {
    let file = load_fixtures();
    let ops: Vec<&str> = file.fixtures.iter().map(|f| f.op.as_str()).collect();

    let required = [
        "r2_score",
        "mean_squared_error",
        "root_mean_squared_error",
        "mean_absolute_error",
        "mean_absolute_percentage_error",
        "median_absolute_error",
        "max_error",
        "explained_variance_score",
        "accuracy_score",
        "precision_score_binary",
        "recall_score_binary",
        "f1_score_binary",
        "roc_auc_score",
        "log_loss",
        "confusion_matrix",
        "hamming_loss",
        "balanced_accuracy_score",
        "matthews_corrcoef",
        "cohen_kappa_score",
        "brier_score_loss",
        "top_k_accuracy_score_k1",
        "top_k_accuracy_score_k2",
        "zero_one_loss_normalized",
        "zero_one_loss_count",
        "average_precision_score",
        "ndcg_score_perfect",
        "ndcg_score_imperfect",
        "dcg_score",
        "label_ranking_average_precision_score",
        "label_ranking_loss",
        "coverage_error",
        "adjusted_rand_score_perfect",
        "adjusted_rand_score_mixed",
        "adjusted_mutual_info_score",
        "normalized_mutual_info_score",
        "homogeneity_score_perfect",
        "completeness_score_perfect",
        "v_measure_score_perfect",
        "fowlkes_mallows_score_perfect",
        "silhouette_score",
        "davies_bouldin_score",
        "calinski_harabasz_score",
    ];

    for r in &required {
        assert!(ops.contains(r), "fixture file missing required op {r:?}");
    }
}
